import{_ as e,o as l,c as t,ag as i}from"./chunks/framework.BqfgOMAh.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh/faq/index.md","filePath":"zh/faq/index.md"}'),o={name:"zh/faq/index.md"};function s(r,a,n,d,h,u){return l(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="连接问题" tabindex="-1">连接问题 <a class="header-anchor" href="#连接问题" aria-label="Permalink to &quot;连接问题&quot;">​</a></h2><h3 id="nexusflow-启动后一直显示未连接" tabindex="-1">NexusFlow 启动后一直显示未连接？ <a class="header-anchor" href="#nexusflow-启动后一直显示未连接" aria-label="Permalink to &quot;NexusFlow 启动后一直显示未连接？&quot;">​</a></h3><p>NexusFlow 与 UE 之间通过 Named Pipe 通信，支持<strong>任意启动顺序</strong>——无论先启动 NexusFlow 还是先启动 UE 编辑器，双方都会自动发现并建立连接。</p><p>如果仍然无法连接，请检查：</p><ul><li><strong>版本是否匹配</strong>：NexusFlow 桌面应用和 UE 插件的版本必须兼容，请确保两端都更新到最新版本</li><li>UE 项目中是否已启用 NexusFlow 插件（编辑 &gt; 插件管理器）</li><li>是否有防火墙或安全软件阻止了通信</li><li>系统中是否运行了多个 NexusFlow 实例</li></ul><div class="tip custom-block"><p class="custom-block-title">版本匹配</p><p>如果近期更新了 NexusFlow 桌面应用，请同时更新 UE 插件到对应版本，避免因版本不匹配导致连接失败。</p></div><h3 id="ue-重启或切换项目后-需要重启-nexusflow-吗" tabindex="-1">UE 重启或切换项目后，需要重启 NexusFlow 吗？ <a class="header-anchor" href="#ue-重启或切换项目后-需要重启-nexusflow-吗" aria-label="Permalink to &quot;UE 重启或切换项目后，需要重启 NexusFlow 吗？&quot;">​</a></h3><p><strong>不需要</strong>。NexusFlow 内置自动重连机制：</p><ul><li>UE 关闭或切换项目时，连接会暂时断开</li><li>NexusFlow 会自动等待 UE 重新连接</li><li>通常在 UE 完全启动后的几秒内自动恢复</li></ul><p>你只需要重启 UE，NexusFlow 会自动处理重连。</p><h2 id="ai-模型" tabindex="-1">AI 模型 <a class="header-anchor" href="#ai-模型" aria-label="Permalink to &quot;AI 模型&quot;">​</a></h2><h3 id="添加模型后验证失败" tabindex="-1">添加模型后验证失败？ <a class="header-anchor" href="#添加模型后验证失败" aria-label="Permalink to &quot;添加模型后验证失败？&quot;">​</a></h3><p>模型验证会向 AI 服务商发送一个测试请求。验证失败的常见原因：</p><table tabindex="0"><thead><tr><th>原因</th><th>解决方法</th></tr></thead><tbody><tr><td>API Key 错误或过期</td><td>检查 Key 是否正确复制，确认有效期</td></tr><tr><td>网络无法连接 API</td><td>检查网络连接，是否需要代理</td></tr><tr><td>模型标识错误</td><td>确认模型名称拼写正确，如 <code>gpt-5.4</code> 而非 <code>gpt54</code></td></tr><tr><td>Custom Provider 配置错误</td><td>检查 API 地址和通讯协议是否匹配</td></tr></tbody></table><h3 id="ai-回复中断或无响应" tabindex="-1">AI 回复中断或无响应？ <a class="header-anchor" href="#ai-回复中断或无响应" aria-label="Permalink to &quot;AI 回复中断或无响应？&quot;">​</a></h3><p>如果 AI 回复到一半中断或完全没有响应，可能的原因：</p><ul><li><strong>账户余额不足</strong>：检查 AI 服务商的账户余额</li><li><strong>服务商限流</strong>：短时间内请求过多，稍后重试</li><li><strong>网络不稳定</strong>：AI 回复使用流式传输，网络波动可能导致中断</li><li><strong>Max Tokens 设置过低</strong>：增大 Max Tokens 值（建议至少 4096）</li></ul><div class="tip custom-block"><p class="custom-block-title">重试方法</p><p>AI 中断后，你可以直接重新发送消息或描述 &quot;继续&quot; 来让 AI 接着回复。</p></div><h3 id="使用-anthropic-claude-模型必须设置-max-tokens" tabindex="-1">使用 Anthropic (Claude) 模型必须设置 Max Tokens？ <a class="header-anchor" href="#使用-anthropic-claude-模型必须设置-max-tokens" aria-label="Permalink to &quot;使用 Anthropic (Claude) 模型必须设置 Max Tokens？&quot;">​</a></h3><p>是的。Anthropic 的 Messages API <strong>要求</strong>必须指定 Max Tokens 参数，这是 Anthropic 的接口规范。</p><ul><li>在添加 Anthropic 模型时，请务必设置 Max Tokens</li><li>建议值：<strong>4096</strong> 或更高</li><li>未设置会导致 API 调用失败</li></ul><div class="warning custom-block"><p class="custom-block-title">必填项</p><p>使用 Anthropic 协议（包括 Custom Provider 选择 Anthropic Messages API 时），Max Tokens 为必填项。详见 <a href="./../guide/settings">设置说明 - AI 模型</a>。</p></div><h3 id="ai-回复的语言与预期不一致" tabindex="-1">AI 回复的语言与预期不一致？ <a class="header-anchor" href="#ai-回复的语言与预期不一致" aria-label="Permalink to &quot;AI 回复的语言与预期不一致？&quot;">​</a></h3><p>AI 回复语言可以独立于界面语言设置：</p><ul><li>进入 <strong>设置 &gt; Agent 配置 &gt; 回复语言</strong></li><li>默认为「跟随界面语言」</li><li>如果界面是英文但需要中文回复，在此处手动选择「简体中文」</li></ul><h3 id="支持哪些-ai-服务提供商-可以用本地模型吗" tabindex="-1">支持哪些 AI 服务提供商？可以用本地模型吗？ <a class="header-anchor" href="#支持哪些-ai-服务提供商-可以用本地模型吗" aria-label="Permalink to &quot;支持哪些 AI 服务提供商？可以用本地模型吗？&quot;">​</a></h3><p>NexusFlow 内置支持以下提供商：</p><ul><li><strong>OpenAI</strong> — GPT 系列</li><li><strong>Anthropic</strong> — Claude 系列</li><li><strong>Google Gemini</strong> — Gemini 系列</li><li><strong>DeepSeek</strong> — DeepSeek 系列</li><li><strong>智谱 GLM</strong> — GLM 系列</li><li><strong>MiniMax</strong> — MiniMax 系列</li><li><strong>通义千问</strong> — Qwen 系列</li><li><strong>Kimi</strong> — Kimi 系列</li></ul><p>通过 <strong>Custom Provider</strong> 可以接入任何兼容 OpenAI / Anthropic / Gemini API 的服务，包括本地部署的模型：</p><ul><li><a href="https://ollama.ai/" target="_blank" rel="noreferrer">Ollama</a></li><li><a href="https://lmstudio.ai/" target="_blank" rel="noreferrer">LM Studio</a></li><li>其他兼容 OpenAI API 的服务</li></ul><p>只需在 Custom Provider 中填写 API 地址并选择对应的通讯协议即可。</p><h2 id="蓝图操作" tabindex="-1">蓝图操作 <a class="header-anchor" href="#蓝图操作" aria-label="Permalink to &quot;蓝图操作&quot;">​</a></h2><h3 id="ai-正在操作蓝图时能中断吗" tabindex="-1">AI 正在操作蓝图时能中断吗？ <a class="header-anchor" href="#ai-正在操作蓝图时能中断吗" aria-label="Permalink to &quot;AI 正在操作蓝图时能中断吗？&quot;">​</a></h3><p><strong>文字生成可以中断，工具操作不能中断。</strong></p><ul><li>✅ AI 正在生成文字回复时 → 可以点击停止按钮中断</li><li>❌ AI 正在执行工具操作（如修改蓝图）时 → 会提示「工具正在执行中，无法中断」</li></ul><p>需要等待当前工具操作完成后才能进行下一步。</p><h3 id="ue-快速菜单点了没有反应" tabindex="-1">UE 快速菜单点了没有反应？ <a class="header-anchor" href="#ue-快速菜单点了没有反应" aria-label="Permalink to &quot;UE 快速菜单点了没有反应？&quot;">​</a></h3><p>快速菜单依赖 NexusFlow 与 UE 的连接。如果菜单无响应：</p><ol><li>检查 NexusFlow 是否已启动</li><li>检查侧边栏底部状态栏是否显示 🟢 绿色连接状态</li><li>如果未连接，参考 <a href="./troubleshooting#无法连接-ue-编辑器">无法连接 UE</a> 进行排查</li></ol><p><strong>关于关卡编辑器工具栏按钮</strong>：当 NexusFlow 未运行时，点击该按钮会显示包含下载链接的通知，而非打开侧边栏。这是设计行为——帮助已安装 UE 插件但尚未安装桌面应用的新用户。</p><div class="warning custom-block"><p class="custom-block-title">前提条件</p><p>快速菜单的所有 AI 操作（右键菜单和蓝图工具栏按钮）都需要 NexusFlow 处于已连接状态。</p></div><h3 id="ai-说找不到蓝图节点" tabindex="-1">AI 说找不到蓝图节点？ <a class="header-anchor" href="#ai-说找不到蓝图节点" aria-label="Permalink to &quot;AI 说找不到蓝图节点？&quot;">​</a></h3><p>AI 操作蓝图前需要获取当前蓝图的上下文信息。请确认：</p><ol><li><strong>已打开目标蓝图</strong> — 在 UE 中双击打开蓝图资产</li><li><strong>UE 连接正常</strong> — 检查状态栏显示绿色连接</li></ol><p>上下文信息会自动同步，不需要手动告诉 AI 你在编辑哪个蓝图。如果 AI 仍然找不到节点，尝试重新打开蓝图或在对话中明确描述目标节点。</p><h2 id="设置与配置" tabindex="-1">设置与配置 <a class="header-anchor" href="#设置与配置" aria-label="Permalink to &quot;设置与配置&quot;">​</a></h2><h3 id="api-key-安全吗-存储在哪里" tabindex="-1">API Key 安全吗？存储在哪里？ <a class="header-anchor" href="#api-key-安全吗-存储在哪里" aria-label="Permalink to &quot;API Key 安全吗？存储在哪里？&quot;">​</a></h3><p>API Key 使用<strong>加密存储</strong>，保存在本地文件中：</p><ul><li>加密文件位置：<code>%APPDATA%/cn.nexusflow.desktop/secrets.enc</code></li><li>设置文件 <code>settings.json</code> <strong>不包含</strong>明文 API Key</li><li>所有密钥仅保存在本地，<strong>不会上传到任何服务器</strong></li></ul><h3 id="配置文件在哪里-如何重置设置" tabindex="-1">配置文件在哪里？如何重置设置？ <a class="header-anchor" href="#配置文件在哪里-如何重置设置" aria-label="Permalink to &quot;配置文件在哪里？如何重置设置？&quot;">​</a></h3><p>NexusFlow 的配置文件位于：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%/cn.nexusflow.desktop/</span></span>
<span class="line"><span>├── settings.json    # 设置（模型配置、外观、快捷键等）</span></span>
<span class="line"><span>├── secrets.enc      # 加密的 API Key</span></span>
<span class="line"><span>└── logs/            # 日志文件</span></span></code></pre></div><p><strong>重置所有设置</strong>：删除 <code>%APPDATA%/cn.nexusflow.desktop/</code> 整个目录，重启 NexusFlow 后会恢复默认设置并重新弹出首次运行向导。</p><div class="danger custom-block"><p class="custom-block-title">注意</p><p>重置设置会清除所有已添加的 AI 模型配置和 API Key，需要重新配置。</p></div><h3 id="修改全局快捷键后没有生效" tabindex="-1">修改全局快捷键后没有生效？ <a class="header-anchor" href="#修改全局快捷键后没有生效" aria-label="Permalink to &quot;修改全局快捷键后没有生效？&quot;">​</a></h3><p>全局快捷键修改后需要注册到操作系统。如果没有生效：</p><ol><li>检查是否与其他应用的快捷键冲突</li><li>尝试更换为其他组合键</li><li><strong>重启 NexusFlow</strong> 使新快捷键生效</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果快捷键完全失效，进入 设置 &gt; 快捷键，点击「恢复默认」重置。</p></div><h2 id="性能与兼容性" tabindex="-1">性能与兼容性 <a class="header-anchor" href="#性能与兼容性" aria-label="Permalink to &quot;性能与兼容性&quot;">​</a></h2><h3 id="操作大型蓝图很慢" tabindex="-1">操作大型蓝图很慢？ <a class="header-anchor" href="#操作大型蓝图很慢" aria-label="Permalink to &quot;操作大型蓝图很慢？&quot;">​</a></h3><p>操作大型蓝图（节点数量多的蓝图）时，NexusFlow 需要：</p><ol><li>读取蓝图的完整数据</li><li>将数据转换并发送给 AI</li><li>AI 分析和生成操作指令</li><li>在 UE 中执行操作</li></ol><p>每个步骤都需要时间，蓝图越大耗时越长。这是 Beta 阶段的正常现象，后续版本会持续优化性能。</p><h3 id="支持哪些-ue-版本" tabindex="-1">支持哪些 UE 版本？ <a class="header-anchor" href="#支持哪些-ue-版本" aria-label="Permalink to &quot;支持哪些 UE 版本？&quot;">​</a></h3><p>NexusFlow 支持以下 UE 版本：</p><ul><li>✅ UE 5.6：完整支持</li><li>✅ UE 5.7：完整支持</li><li>❌ UE 5.5 及更早版本：不支持（需要 ONNX Runtime 1.20+，UE 5.5 内置版本过低）</li><li>❌ UE 4.x：不支持</li></ul><div class="warning custom-block"><p class="custom-block-title">版本要求</p><p>NexusFlow 使用 UE 内置的 ONNX Runtime（NNERuntimeORT）进行 RAG 语义搜索。UE 5.6 起才内置兼容版本的 ONNX Runtime。</p></div><h3 id="支持-macos-吗" tabindex="-1">支持 macOS 吗？ <a class="header-anchor" href="#支持-macos-吗" aria-label="Permalink to &quot;支持 macOS 吗？&quot;">​</a></h3><p>当前仅支持 <strong>Windows 10/11</strong>。</p><p>macOS 版本在规划中，但由于系统级别的权限限制（App Sandbox 对进程间通信的约束），macOS 支持需要额外的适配工作。</p><h2 id="更多帮助" tabindex="-1">更多帮助 <a class="header-anchor" href="#更多帮助" aria-label="Permalink to &quot;更多帮助&quot;">​</a></h2><p>如果以上内容没有解决你的问题：</p><ul><li>查看 <a href="./troubleshooting">故障排除指南</a> 获取详细的诊断步骤</li><li>在 <a href="https://github.com/maxzhao/NexusFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提交问题反馈</li></ul>`,74)])])}const g=e(o,[["render",s]]);export{p as __pageData,g as default};
